UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('9090-breathing-with-reach', 'Use hands on belly/ribs. Make it simple: "fill the balloon, blow out slow."', 'No default gender adjustment; scale by trunk control, comfort, pregnancy/postpartum status, and breathing strategy.'),
  ('crocodile-breathing', '3–5 slow breaths only; use "belly pushes the floor" cue.', 'No male/female default change.'),
  ('full-body-joint-cars-flow', 'Make it a "joint check game"; 1–2 circles per joint.', 'No gender default change.'),
  ('cat-cow', 'Use animal cues: "angry cat / happy cow."', 'No gender default change.'),
  ('quadruped-spinal-circles', 'Use "draw a circle with your back" cue.', 'No gender default change.'),
  ('quadruped-thread-the-needle', 'Keep hand on head instead of reaching long.', 'No gender default change.'),
  ('side-lying-open-book', 'Use smaller range and "open the book" cue.', 'No gender default change.'),
  ('9090-hip-switch', 'Allow hands behind body and larger knee angles.', 'No gender default change; scale by hip anatomy, comfort, and control.'),
  ('worlds-greatest-stretch', 'Use hands on blocks or elevated surface.', 'No gender default change.'),
  ('inchworm-walkout', 'Shorten range; walk hands to elevated box.', 'No gender default change; scale by trunk control, wrist tolerance, and hamstring range.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'youth_beginner', 'youth beginner', 'baseline', v.guidance,
  CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('9090-breathing-with-reach', 'Use hands on belly/ribs. Make it simple: "fill the balloon, blow out slow."', 'No default gender adjustment; scale by trunk control, comfort, pregnancy/postpartum status, and breathing strategy.'),
  ('crocodile-breathing', '3–5 slow breaths only; use "belly pushes the floor" cue.', 'No male/female default change.'),
  ('full-body-joint-cars-flow', 'Make it a "joint check game"; 1–2 circles per joint.', 'No gender default change.'),
  ('cat-cow', 'Use animal cues: "angry cat / happy cow."', 'No gender default change.'),
  ('quadruped-spinal-circles', 'Use "draw a circle with your back" cue.', 'No gender default change.'),
  ('quadruped-thread-the-needle', 'Keep hand on head instead of reaching long.', 'No gender default change.'),
  ('side-lying-open-book', 'Use smaller range and "open the book" cue.', 'No gender default change.'),
  ('9090-hip-switch', 'Allow hands behind body and larger knee angles.', 'No gender default change; scale by hip anatomy, comfort, and control.'),
  ('worlds-greatest-stretch', 'Use hands on blocks or elevated surface.', 'No gender default change.'),
  ('inchworm-walkout', 'Shorten range; walk hands to elevated box.', 'No gender default change; scale by trunk control, wrist tolerance, and hamstring range.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
