-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('9090-breathing-with-reach', 'The 90/90 position gives the athlete a low-threat way to organize the ribcage, pelvis, and diaphragm. It is especially useful when athletes default to chest breathing, rib flare, excessive lumbar extension, or poor trunk bracing. Functional Movement Systems describes the drill as a way to practice diaphragmatic breathing with the hips and knees at 90 degrees and emphasizes slow nasal breathing with a longer exhale.', 'Belongs in Mobilize (breathing_reset) — opens trunk access and down-regulates before mobility or skill work.', 'First 1–3 minutes of session, especially before mobility, tumbling, sprint mechanics, lifting, or athletes who arrive overextended, anxious, or stiff.', 'Do not use as a long relaxation block or substitute for raising temperature when athletes need active warm-up.', 'Scale by trunk control, comfort in supine, and breathing strategy; reduce reps/duration for youth.'),
  ('crocodile-breathing', 'Crocodile breathing places the athlete prone so the floor gives immediate feedback. When they inhale, they should feel the belly and lower ribs expand into the ground rather than lifting the shoulders. Functional Movement Systems describes it as a diaphragmatic breathing exercise performed prone with relaxed chest, arms, and neck.', 'Belongs in Mobilize (breathing_reset) — nervous-system and trunk reset before active prep.', 'Early session, especially for athletes who chest-breathe, brace poorly, rush, or need a low-threat nervous-system reset.', 'Do not spend too long here before a high-energy class that needs temperature raise.', 'Regress to seated breathing for pregnancy or prone discomfort.'),
  ('full-body-joint-cars-flow', 'Joint CARs are useful because they ask the athlete to actively move through available range rather than passively fall into a stretch. GMB''s joint mobility guide frames preparation mobility as a short, light check-in before training, aimed at feeling coordinated, noticing restrictions, and preparing joints for activity rather than turning mobility into a workout.', 'Belongs in Mobilize (joint_scan) — systematic joint-by-joint readiness before specific prep.', 'Early, after breathing or light locomotion.', 'Do not treat CARs as static stretching or spend excessive time when session needs specificity.', 'Reduce joints covered or circle count for youth and beginners.'),
  ('cat-cow', 'Cat-Cow teaches the athlete to move between spinal flexion and extension while linking pelvis, ribs, and breathing. The Prehab Guys describe it as a drill for back and pelvic body awareness that promotes global mobility and comfort moving in and out of spinal flexion and extension.', 'Belongs in Mobilize (spinal_mobility) — foundational spine access before integrated patterns.', 'Early mobility sequence, especially before tumbling, crawling, lifting, or trunk-control work.', 'Do not rush reps or use painful end ranges when athlete needs stability instead.', 'Elevate hands on bench or use seated cat-cow for older adults.'),
  ('quadruped-spinal-circles', 'Cat-Cow is mostly flexion/extension. Spinal circles add lateral movement and blended motion, which is useful because athletes rarely move in clean single-plane patterns. GMB includes quadruped spinal circles in its daily diagnostic mobility sequence and describes the focus as full back mobility.', 'Belongs in Mobilize (spinal_mobility) — adds 3D spine exploration after basic flex/extend.', 'After Cat-Cow or as an alternative when the athlete needs more 3D spine motion.', 'Do not move only the head or dump into lumbar extension.', 'Elevate hands or use seated torso circles for limited wrist/knee tolerance.'),
  ('quadruped-thread-the-needle', 'Thread the Needle gives the athlete a stable quadruped base so the coach can bias thoracic rotation instead of letting the athlete compensate through the hips or low back. Elite Performance Institute describes the drill as a low-load way to loosen the midback and shoulder, improve thoracic rotation, and use daily or in warm-ups for overhead and rotational training.', 'Belongs in Mobilize (thoracic_rotation) — T-spine access before overhead or rotational work.', 'Before tumbling, overhead work, crawling, throwing, rotational drills, or upper-body strength.', 'Do not let lumbar spine twist or force painful shoulder range.', 'Elevate hands on bench for wrist/knee demand reduction.'),
  ('side-lying-open-book', 'The side-lying setup reduces lower-body demand and lets the coach focus on thoracic/rib rotation. This is useful for athletes who over-rotate through the pelvis or low back during standing rotation drills. The Prehab Guys emphasize that thoracic mobility matters for neck, shoulder, low-back, and functional movement, and their thoracic rotation guidance stresses controlling compensation and using breath through rotation.', 'Belongs in Mobilize (thoracic_rotation) — supported T-spine rotation with minimal hip demand.', 'Before tumbling, overhead training, rotational skill, throwing, pressing, crawling, and sprint mechanics.', 'Do not force shoulder to floor or let top knee lift.', 'Support head with pillow; pad between knees for hip control.'),
  ('9090-hip-switch', 'Athletic hips need both external and internal rotation. The 90/90 hip switch exposes both sides in one drill and teaches the athlete to move through hip rotation without collapsing posture. The Prehab Guys describe beginning in a seated 90/90 position, hinging toward the front knee, then rotating the legs to the other side while keeping heels on the ground.', 'Belongs in Mobilize (hip_rotation) — seated IR/ER access before squat, lunge, or sprint prep.', 'Before squatting, lunging, tumbling, sprint mechanics, lateral movement, or rotational training.', 'Do not use momentum to flop between sides or force pinching ranges.', 'Elevate hips on block; widen knee angles for youth.'),
  ('worlds-greatest-stretch', 'This drill is valuable because it integrates several high-need athletic positions: deep lunge, hip extension, hamstring length, thoracic rotation, and shoulder reach. NASM''s dynamic stretching examples include multiplanar lunges with reach as functional flexibility progressions, and Squat University describes the World''s Greatest Stretch as a way to open the hips and thoracic spine.', 'Belongs in Integrate (integrated_mobility) — multi-joint flow after isolated mobility.', 'After basic joint mobility, before sprint mechanics, plyometrics, agility, strength, or tumbling.', 'Do not hold static stretches or rush through positions before power work.', 'Elevate hands on bench; break into lunge reach + hamstring shift for beginners.'),
  ('inchworm-walkout', 'The inchworm is a bridge between mobility and integrated body control. It exposes the hamstrings through a hinge, then asks the athlete to organize shoulders, wrists, ribs, pelvis, and trunk in a plank. The Prehab Guys describe the walking inchworm as reaching toward the floor, walking hands to a high plank, stepping feet toward the hands, and standing back up; they note hamstring stretch and shoulder work as key sensations.', 'Belongs in Integrate (integrated_mobility) — late Prepare/Access bridge before higher-intent work.', 'Late Prepare / Access, after basic spine/hip/shoulder access, before Skill, Output, or Capacity.', 'Do not use before grip/wrist-heavy tumbling if athlete is already fatigued or cannot hold plank.', 'Elevated surface or wall walkout for limited hamstring/wrist tolerance.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();
